64	void mask_to_adj_matrix_small_N(uint16_t mask, int N_nodes, bool adj_matrix[][N_MAX_GED_CAP]) {
65	    int bit_idx = 0;
66	    for (int i = 0; i < N_nodes; ++i) {
67	        adj_matrix[i][i] = false;
68	        for (int j = i + 1; j < N_nodes; ++j) {
69	            adj_matrix[i][j] = adj_matrix[j][i] = ((mask >> bit_idx) & 1);
70	            bit_idx++;
71	        }
72	    }
73	}
74	
75	uint16_t adj_matrix_to_mask_small_N(int N_nodes, const bool adj_matrix[][N_MAX_GED_CAP], const std::vector<int>& p_perm) {
76	    uint16_t mask = 0;
77	    int bit_idx = 0;
78	    for (int i = 0; i < N_nodes; ++i) {
79	        for (int j = i + 1; j < N_nodes; ++j) {
80	            if (adj_matrix[p_perm[i]][p_perm[j]]) { 
81	                mask |= (1U << bit_idx);
82	            }
83	            bit_idx++;
84	        }
85	    }
86	    return mask;
87	}
