105	int calculate_edit_distance_one_perm_small_N(
106	    const std::array<std::array<bool, N_MAX_GED_CAP>, N_MAX_GED_CAP>& g_j_adj_template 
107	) {
108	    int diff_count = 0;
109	    for (int i = 0; i < N_ACTUAL; ++i) { 
110	        for (int j = i + 1; j < N_ACTUAL; ++j) { 
111	            bool template_has_edge = g_j_adj_template[i][j]; 
112	            bool current_Hk_has_edge = CURRENT_GRAPH_ADJ_QUERY[P_VERTS_PERM_QUERY[i]][P_VERTS_PERM_QUERY[j]];
113	            if (current_Hk_has_edge != template_has_edge) {
114	                diff_count++;
115	            }
116	        }
117	    }
118	    return diff_count;
119	}
