121	int min_edit_distance_global_perm_small_N(
122	    const std::array<std::array<bool, N_MAX_GED_CAP>, N_MAX_GED_CAP>& g_j_adj_template
123	) { 
124	    if (L_ACTUAL == 0) return 0;
125	
126	    std::iota(P_VERTS_PERM_QUERY.begin(), P_VERTS_PERM_QUERY.end(), 0); 
127	    int min_dist = L_ACTUAL + 1; 
128	    
129	    long long N_factorial = 1;
130	    for(int i=1; i<=N_ACTUAL; ++i) N_factorial *= i;
131	
132	    long long ops_count = 0;
133	    do {
134	        int current_dist = calculate_edit_distance_one_perm_small_N(g_j_adj_template);
135	        min_dist = std::min(min_dist, current_dist);
136	        if (min_dist == 0) break; 
137	        
138	        ops_count++;
139	        if (ops_count >= N_factorial) break; 
140	    } while (std::next_permutation(P_VERTS_PERM_QUERY.begin(), P_VERTS_PERM_QUERY.end()));
141	    
142	    return min_dist;
143	}
