151	std::string generate_random_graph_string_large_n(int num_edges, int current_L) { 
152	    std::string s_out(current_L, '0');
153	    if (num_edges <= 0 || current_L == 0) return s_out;
154	    if (num_edges >= current_L) {
155	        std::fill(s_out.begin(), s_out.end(), '1');
156	        return s_out;
157	    }
158	    std::vector<int> edge_indices(current_L);
159	    std::iota(edge_indices.begin(), edge_indices.end(), 0);
160	    std::shuffle(edge_indices.begin(), edge_indices.end(), RND_ENGINE);
161	    for (int i = 0; i < num_edges; ++i) {
162	        s_out[edge_indices[i]] = '1';
163	    }
164	    return s_out;
165	}
