171	void string_to_adj_matrix_query(const std::string& s, int N_nodes) {
172	    int char_idx = 0;
173	    for(int i=0; i<N_nodes; ++i) { 
174	        CURRENT_GRAPH_ADJ_QUERY[i][i] = false;
175	        for(int j=i+1; j<N_nodes; ++j) {
176	            if (char_idx < (int)s.length()) {
177	                CURRENT_GRAPH_ADJ_QUERY[i][j] = CURRENT_GRAPH_ADJ_QUERY[j][i] = (s[char_idx++] == '1');
178	            } else { 
179	                CURRENT_GRAPH_ADJ_QUERY[i][j] = CURRENT_GRAPH_ADJ_QUERY[j][i] = false;
180	            }
181	        }
182	    }
183	}
