186	int main() {
187	    std::ios_base::sync_with_stdio(false);
188	    std::cin.tie(NULL);
189	    
190	    unsigned int seed_val = std::chrono::duration_cast<std::chrono::nanoseconds>(std::chrono::high_resolution_clock::now().time_since_epoch()).count();
191	    RND_ENGINE.seed(seed_val);
192	
193	    int M_graphs;
194	    double epsilon_noise_rate;
195	    std::cin >> M_graphs >> epsilon_noise_rate;
196	    
197	    int N_for_GED_strat;
198	    if (M_graphs <= 11) N_for_GED_strat = 4; 
199	    else if (M_graphs <= 34) N_for_GED_strat = 5; 
200	    else N_for_GED_strat = N_MAX_GED_CAP; 
201	
202	    const double K_SEP = 2.5; 
203	    double L_ideal;
204	    double L_ideal_numerator = K_SEP * K_SEP * (M_graphs > 1 ? (M_graphs - 1.0) * (M_graphs - 1.0) : 1.0) * 
205	                               epsilon_noise_rate * (1.0 - epsilon_noise_rate);
206	    double L_ideal_denominator_factor = (0.5 - epsilon_noise_rate);
207	    double L_ideal_denominator = L_ideal_denominator_factor * L_ideal_denominator_factor;
208	    
209	    if (std::abs(0.5 - epsilon_noise_rate) < 1e-9) { 
210	        L_ideal = (100.0 * 99.0) / 2.0; 
211	    } else {
212	        L_ideal = L_ideal_numerator / L_ideal_denominator;
213	    }
214	    if (L_ideal < 0) L_ideal = 0; 
215	    
216	    int N_candidate_EC = 4; 
217	    if (L_ideal > 1e-9) { 
218	         double discriminant = 1.0 + 8.0 * L_ideal; 
219	         if (discriminant >=0) { 
220	            N_candidate_EC = static_cast<int>(std::ceil((1.0 + std::sqrt(discriminant)) / 2.0));
221	         } else { 
222	            N_candidate_EC = 100; 
223	         }
224	    }
225	    N_candidate_EC = std::max(4, N_candidate_EC); 
226	    N_candidate_EC = std::min(100, N_candidate_EC); 
227	
228	    if (epsilon_noise_rate < 0.01) {
229	        current_strategy = Strategy::GED; N_ACTUAL = N_for_GED_strat;
230	    } else { 
231	        if (N_candidate_EC > N_for_GED_strat) { 
232	             current_strategy = Strategy::EDGE_COUNT; N_ACTUAL = N_candidate_EC;
233	        } else { 
234	            current_strategy = Strategy::GED; N_ACTUAL = N_for_GED_strat;
235	        }
236	    }
237	    N_ACTUAL = std::min(100, std::max(4, N_ACTUAL)); // Final check on N_ACTUAL bounds
238	            
239	    L_ACTUAL = N_ACTUAL * (N_ACTUAL - 1) / 2;
240	    std::cout << N_ACTUAL << std::endl;
241	
242	#ifdef DEBUG_OUTPUT
243	    std::cerr << "# M=" << M_graphs << ", eps=" << epsilon_noise_rate << std::endl;
244	    std::cerr << "# Chosen N=" << N_ACTUAL << ", Strategy=" << (current_strategy == Strategy::GED ? "GED" : "EDGE_COUNT") << std::endl;
245	    std::cerr << "# L_ideal=" << L_ideal << ", N_candidate_EC=" << N_candidate_EC << ", N_for_GED_strat=" << N_for_GED_strat << std::endl;
246	#endif
247	
248	    if (current_strategy == Strategy::GED) {
249	        P_VERTS_PERM_QUERY.resize(N_ACTUAL); CANON_P_PERM.resize(N_ACTUAL);
250	        
251	        if (N_ACTUAL == 6) {
252	            available_canonical_masks = PRECOMPUTED_CANONICAL_MASKS_N6;
253	        } else { 
254	            std::set<uint16_t> unique_masks_set;
255	            if (L_ACTUAL > 0) { 
256	                for (unsigned int i = 0; i < (1U << L_ACTUAL); ++i) {
257	                    unique_masks_set.insert(get_canonical_mask(static_cast<uint16_t>(i)));
258	                }
259	            } else { 
260	                unique_masks_set.insert(0); 
261	            }
262	            available_canonical_masks.assign(unique_masks_set.begin(), unique_masks_set.end());
263	        }
264	        
265	        int num_total_isos = available_canonical_masks.size();
266	#ifdef DEBUG_OUTPUT
267	    std::cerr << "# Num non-isomorphic graphs for N=" << N_ACTUAL << " is " << num_total_isos << std::endl;
268	#endif
269	        mask_to_idx_map.clear();
270	        for(int i=0; i<num_total_isos; ++i) mask_to_idx_map[available_canonical_masks[i]] = i;
271	
272	        if (num_total_isos > 0) {
273	            all_pairwise_ged_cache.assign(num_total_isos, std::vector<int>(num_total_isos, 0));
274	            bool graph_i_adj_cstyle[N_MAX_GED_CAP][N_MAX_GED_CAP]; 
275	            std::array<std::array<bool, N_MAX_GED_CAP>, N_MAX_GED_CAP> graph_j_adj_stdarray;
276	
277	            for (int i = 0; i < num_total_isos; ++i) {
278	                mask_to_adj_matrix_small_N(available_canonical_masks[i], N_ACTUAL, graph_i_adj_cstyle);
279	                for(int r=0; r<N_ACTUAL; ++r) for(int c=0; c<N_ACTUAL; ++c) CURRENT_GRAPH_ADJ_QUERY[r][c] = graph_i_adj_cstyle[r][c];
280	
281	                for (int j = i + 1; j < num_total_isos; ++j) {
282	                    bool temp_adj_for_gj[N_MAX_GED_CAP][N_MAX_GED_CAP];
283	                    mask_to_adj_matrix_small_N(available_canonical_masks[j], N_ACTUAL, temp_adj_for_gj);
284	                    for(int r=0; r<N_ACTUAL; ++r) for(int c=0; c<N_ACTUAL; ++c) graph_j_adj_stdarray[r][c] = temp_adj_for_gj[r][c];
285	                    
286	                    all_pairwise_ged_cache[i][j] = all_pairwise_ged_cache[j][i] = min_edit_distance_global_perm_small_N(graph_j_adj_stdarray);
287	                }
288	            }
289	        }
290	        
291	        chosen_mask_indices_greedy.clear();
292	        std::vector<bool> is_chosen_idx(num_total_isos, false);
293	
294	        if (num_total_isos > 0) { 
295	            if (mask_to_idx_map.count(0)) { 
296	                int zero_idx = mask_to_idx_map.at(0);
297	                if (chosen_mask_indices_greedy.size() < (size_t)M_graphs) {
298	                    chosen_mask_indices_greedy.push_back(zero_idx); 
299	                    is_chosen_idx[zero_idx] = true;
300	                }
301	            }
302	            if (L_ACTUAL > 0 && chosen_mask_indices_greedy.size() < (size_t)M_graphs) {
303	                uint16_t complete_mask_val = (1U << L_ACTUAL) - 1; 
304	                uint16_t canonical_complete_mask = get_canonical_mask(complete_mask_val); 
305	                if (mask_to_idx_map.count(canonical_complete_mask)) {
306	                    int complete_idx = mask_to_idx_map.at(canonical_complete_mask);
307	                    if (!is_chosen_idx[complete_idx]) { 
308	                         chosen_mask_indices_greedy.push_back(complete_idx);
309	                         is_chosen_idx[complete_idx] = true;
310	                    }
311	                }
312	            }
313	        }
314	        
315	        for (int k_count = chosen_mask_indices_greedy.size(); k_count < M_graphs; ++k_count) {
316	            if (chosen_mask_indices_greedy.size() >= (size_t)num_total_isos) { 
317	                break;
318	            }
319	
320	            int best_new_idx_to_add = -1; 
321	            int max_of_min_distances_found = -1; 
322	
323	            for (int cand_idx = 0; cand_idx < num_total_isos; ++cand_idx) {
324	                if (is_chosen_idx[cand_idx]) continue;
325	
326	                int current_cand_min_dist_to_existing_G;
327	                if (chosen_mask_indices_greedy.empty()) { 
328	                     current_cand_min_dist_to_existing_G = L_ACTUAL + 1; 
329	                } else {
330	                    current_cand_min_dist_to_existing_G = L_ACTUAL + 1;
331	                    for (int chosen_idx : chosen_mask_indices_greedy) {
332	                        current_cand_min_dist_to_existing_G = std::min(current_cand_min_dist_to_existing_G, all_pairwise_ged_cache[cand_idx][chosen_idx]);
333	                    }
334	                }
335	                
336	                if (current_cand_min_dist_to_existing_G > max_of_min_distances_found) {
337	                    max_of_min_distances_found = current_cand_min_dist_to_existing_G;
338	                    best_new_idx_to_add = cand_idx;
339	                }
340	            }
341	            
342	            if (best_new_idx_to_add != -1) { 
343	                chosen_mask_indices_greedy.push_back(best_new_idx_to_add); 
344	                is_chosen_idx[best_new_idx_to_add] = true; 
345	            } else {
346	                break; 
347	            }
348	        }
349	        
350	        int num_distinct_chosen_graphs = chosen_mask_indices_greedy.size();
351	        if (num_distinct_chosen_graphs < M_graphs) {
352	            int fallback_idx = 0; 
353	            if (num_total_isos > 0) { 
354	                if (mask_to_idx_map.count(0)) { 
355	                    fallback_idx = mask_to_idx_map.at(0); 
356	                } 
357	            }
358	            
359	            for (int k_idx = num_distinct_chosen_graphs; k_idx < M_graphs; ++k_idx) {
360	                 if (num_total_isos > 0) {
361	                    chosen_mask_indices_greedy.push_back(fallback_idx);
362	                 } else { 
363	                    chosen_mask_indices_greedy.push_back(0); 
364	                 }
365	            }
366	        }
367	#ifdef DEBUG_OUTPUT
368	    std::cerr << "# Chosen mask indices (size " << chosen_mask_indices_greedy.size() << "): ";
369	    if (!available_canonical_masks.empty()){ // Check before accessing
370	        for(int idx : chosen_mask_indices_greedy) {
371	            if (idx < available_canonical_masks.size()) std::cerr << idx << " (" << available_canonical_masks[idx] << ") ";
372	            else std::cerr << idx << " (OOB) ";
373	        }
374	    }
375	    std::cerr << std::endl;
376	#endif
377	        
378	        G_ADJS_CHOSEN_GED.resize(M_graphs);
379	        for (int k_idx = 0; k_idx < M_graphs; ++k_idx) {
380	            uint16_t mask_to_print = 0; 
381	            if (k_idx < chosen_mask_indices_greedy.size() && 
382	                !available_canonical_masks.empty() && 
383	                chosen_mask_indices_greedy[k_idx] < available_canonical_masks.size()) {
384	                 mask_to_print = available_canonical_masks[chosen_mask_indices_greedy[k_idx]];
385	            } else if (L_ACTUAL == 0 && k_idx < chosen_mask_indices_greedy.size()) { 
386	                 mask_to_print = 0;
387	            }
388	            
389	            bool temp_adj_cstyle[N_MAX_GED_CAP][N_MAX_GED_CAP];
390	            mask_to_adj_matrix_small_N(mask_to_print, N_ACTUAL, temp_adj_cstyle);
391	            for(int r=0; r<N_ACTUAL; ++r) for(int c=0; c<N_ACTUAL; ++c) G_ADJS_CHOSEN_GED[k_idx][r][c] = temp_adj_cstyle[r][c];
392	            
393	            std::string s_out = "";
394	            if (L_ACTUAL > 0) {
395	                for (int bit_idx = 0; bit_idx < L_ACTUAL; ++bit_idx) {
396	                    s_out += ((mask_to_print >> bit_idx) & 1) ? '1' : '0';
397	                }
398	            }
399	            std::cout << s_out << std::endl;
400	        }
401	
402	    } else { 
403	        G_EDGE_COUNTS_LARGE_N.resize(M_graphs); G_STRINGS_CHOSEN_LARGE_N.resize(M_graphs);
404	        if (M_graphs == 1) { 
405	             G_EDGE_COUNTS_LARGE_N[0] = (L_ACTUAL > 0) ? L_ACTUAL / 2 : 0; 
406	        } else { 
407	            for (int k=0; k<M_graphs; ++k) G_EDGE_COUNTS_LARGE_N[k] = static_cast<int>(std::round((double)k * L_ACTUAL / (M_graphs - 1.0)));
408	            
409	            for (int k=0; k<M_graphs-1; ++k) {
410	                if (G_EDGE_COUNTS_LARGE_N[k+1] <= G_EDGE_COUNTS_LARGE_N[k]) {
411	                    G_EDGE_COUNTS_LARGE_N[k+1] = G_EDGE_COUNTS_LARGE_N[k] + 1;
412	                }
413	            }
414	            if (M_graphs > 0 && G_EDGE_COUNTS_LARGE_N[M_graphs-1] > L_ACTUAL) { // M_graphs > 0 check
415	                int exceso = G_EDGE_COUNTS_LARGE_N[M_graphs-1] - L_ACTUAL;
416	                for (int k=0; k<M_graphs; ++k) {
417	                    G_EDGE_COUNTS_LARGE_N[k] -= exceso;
418	                }
419	            }
420	            for (int k=0; k<M_graphs; ++k) G_EDGE_COUNTS_LARGE_N[k] = std::min(L_ACTUAL, std::max(0, G_EDGE_COUNTS_LARGE_N[k]));
421	            
422	            for (int k=0; k<M_graphs-1; ++k) {
423	                 G_EDGE_COUNTS_LARGE_N[k+1] = std::max(G_EDGE_COUNTS_LARGE_N[k+1], G_EDGE_COUNTS_LARGE_N[k] + 1);
424	            }
425	            for (int k=0; k<M_graphs; ++k) G_EDGE_COUNTS_LARGE_N[k] = std::min(L_ACTUAL, std::max(0, G_EDGE_COUNTS_LARGE_N[k]));
426	        }
427	
428	        for (int k=0; k<M_graphs; ++k) {
429	            G_STRINGS_CHOSEN_LARGE_N[k] = generate_random_graph_string_large_n(G_EDGE_COUNTS_LARGE_N[k], L_ACTUAL);
430	            std::cout << G_STRINGS_CHOSEN_LARGE_N[k] << std::endl;
431	        }
432	    }
