            double diff = degrees[i] - mu_nonhub;
            score += diff * diff;
        }
        for (int i = num_nonhubs; i < N_ACTUAL; ++i) {
            double diff = degrees[i] - mu_hub;
            score += diff * diff;
        }

        if (score < best_score) {
            best_score = score;
            best_j = j;
        }
    }

    std::cout << best_j << std::endl;
}

